// Payload v2 modular desde buildExportPayload()
let raw;
try {
  raw = typeof $input.first().json.body === 'string'
    ? JSON.parse($input.first().json.body)
    : ($input.first().json.body || $input.first().json);
} catch(e) {
  raw = $input.first().json;
}

const meta = raw.meta || {};
const m1   = raw.modulo_1_configuracion || {};
const m2b  = raw.modulo_2b_severidad_consolidada || {};
const m4   = raw.modulo_4_responsables || {};
const m4b  = raw.modulo_4b_flujos_revision || {};
const m5   = raw.modulo_5_observaciones || {};

// ── Procesos ──
const procesosEstandar = Object.entries(m1.tiposEvaluacion || {})
  .filter(([,v]) => v.activo).map(([,v]) => v.nombre).join(', ');
const procesosCustom = (m1.procesosPersonalizados || [])
  .filter(p => p.activo).map(p => p.nombre).join(', ');

// ── Alertas graves consolidadas ──
const alertasGraves = (m2b.alertas || []).filter(a => a.severidadFinal === 'grave');
const alertasGravesTotal = alertasGraves.length;
const alertasGravesGrupos = [...new Set(alertasGraves.map(a => a.grupo))].join(', ');

// ── Revisores por grupo ──
const porTema = m4b.porTema || {};
const revisoresLinea = Object.entries(porTema).map(([g, data]) => {
  const r = (data.revisores || [])[0];
  const nombre = r ? (r.nombre || r.email || 'Sin asignar') : 'Sin asignar';
  return `${g}: ${nombre}`;
}).join(' | ');

// ── Responsables por área ──
const AREAS = ['abastecimiento','cumplimiento','finanzas','legal'];
const LABELS = { abastecimiento:'Abastecimiento', cumplimiento:'Cumplimiento', finanzas:'Finanzas', legal:'Legal' };
const porArea = m4.porArea || {};
const resps = {};
AREAS.forEach(a => {
  resps[`resp_${a}_nombre`] = porArea[a]?.encargado?.nombre || '';
  resps[`resp_${a}_email`]  = porArea[a]?.encargado?.email  || '';
  resps[`guardado_${a}`]    = porArea[a]?.guardado ? 'sí' : 'no';
});

// ── Notas por área ──
const notasAreas = AREAS.map(a => {
  const n = m5.observacionesPorArea?.[a];
  return n ? `${LABELS[a]}: ${n}` : '';
}).filter(Boolean).join(' | ');

// ── Mensaje Slack ──
const alertasSlack = Object.entries(porTema).map(([g, data]) => {
  const r = (data.revisores || [])[0];
  const revisor = r ? (r.nombre || r.email || 'Sin asignar') : 'Sin asignar';
  const chips = (data.alertasGraves || []).join(', ');
  return `• 🔴 *${g}* → ${revisor}\n  _${chips}_`;
}).join('\n');

const respSlack = AREAS
  .filter(a => porArea[a]?.encargado?.nombre || porArea[a]?.encargado?.email)
  .map(a => {
    const enc = porArea[a].encargado;
    return `• *${LABELS[a]}:* ${enc.nombre || ''} ${enc.email ? `(${enc.email})` : ''}`.trim();
  }).join('\n');

const fechaFormato = meta.timestamp
  ? new Date(meta.timestamp).toLocaleDateString('es-CL', { day:'2-digit', month:'2-digit', year:'numeric', hour:'2-digit', minute:'2-digit' })
  : '';

const slackLines = [
  ':clipboard: *Nueva política de DD Proveedores completada*',
  '',
  `*Empresa:* ${meta.empresa || '(sin nombre)'}`,
  `*Email CS:* ${meta.email || '(sin email)'}`,
  `*Fecha:* ${fechaFormato}`,
  `*Áreas participantes:* ${(meta.areasParticipantes || []).join(', ')}`,
  '',
  `*Procesos activos:* ${[procesosEstandar, procesosCustom].filter(Boolean).join(' + ') || 'Ninguno'}`,
  '',
  alertasGravesTotal > 0
    ? `*Alertas graves (${alertasGravesTotal}) y revisores:*\n${alertasSlack}`
    : '*Alertas graves:* ninguna',
  '',
  respSlack ? `*Responsables por área:*\n${respSlack}` : '',
  m5.notasSincronizacion ? `\n*Notas de sincronización:* _${m5.notasSincronizacion}_` : '',
].filter(s => s !== undefined).join('\n');

return [{ json: {
  // Meta
  empresa:              meta.empresa || '',
  email:                meta.email || '',
  timestamp:            meta.timestamp || '',
  session_id:           meta.sessionId || '',
  areas_participantes:  (meta.areasParticipantes || []).join(', '),
  // Procesos
  procesos_estandar:    procesosEstandar,
  procesos_custom:      procesosCustom,
  // Alertas
  alertas_graves_total: alertasGravesTotal,
  alertas_graves_grupos: alertasGravesGrupos,
  revisores_por_grupo:  revisoresLinea,
  // Responsables
  ...resps,
  // Notas
  notas_areas:          notasAreas,
  notas_sincronizacion: m5.notasSincronizacion || '',
  // Para Slack
  _slack_msg: slackLines,
}}];
